var aria = aria || {};

/**
 * @description
 *  Key code constants
 */
aria.KeyCode = {
  BACKSPACE: 8,
  TAB: 9,
  RETURN: 13,
  SHIFT: 16,
  ESC: 27,
  SPACE: 32,
  PAGE_UP: 33,
  PAGE_DOWN: 34,
  END: 35,
  HOME: 36,
  LEFT: 37,
  UP: 38,
  RIGHT: 39,
  DOWN: 40,
  DELETE: 46,
};

aria.Utils = aria.Utils || {};

// Polyfill src https://developer.mozilla.org/en-US/docs/Web/API/Element/matches
aria.Utils.matches = function (element, selector) {
  if (!Element.prototype.matches) {
    Element.prototype.matches =
      Element.prototype.matchesSelector ||
      Element.prototype.mozMatchesSelector ||
      Element.prototype.msMatchesSelector ||
      Element.prototype.oMatchesSelector ||
      Element.prototype.webkitMatchesSelector ||
      function (s) {
        var matches = element.parentNode.querySelectorAll(s);
        var i = matches.length;
        while (--i >= 0 && matches.item(i) !== this) {
          // empty
        }
        return i > -1;
      };
  }

  return element.matches(selector);
};

aria.Utils.remove = function (item) {
  if (item.remove && typeof item.remove === 'function') {
    return item.remove();
  }
  if (
    item.parentNode &&
    item.parentNode.removeChild &&
    typeof item.parentNode.removeChild === 'function'
  ) {
    return item.parentNode.removeChild(item);
  }
  return false;
};

aria.Utils.isFocusable = function (element) {
  if (element.tabIndex < 0) {
    return false;
  }

  if (element.disabled) {
    return false;
  }

  switch (element.nodeName) {
    case 'A':
      return !!element.href && element.rel != 'ignore';
    case 'INPUT':
      return element.type != 'hidden';
    case 'BUTTON':
    case 'SELECT':
    case 'TEXTAREA':
      return true;
    default:
      return false;
  }
};

aria.Utils.getAncestorBySelector = function (element, selector) {
  if (!aria.Utils.matches(element, selector + ' ' + element.tagName)) {
    // Element is not inside an element that matches selector
    return null;
  }

  // Move up the DOM tree until a parent matching the selector is found
  var currentNode = element;
  var ancestor = null;
  while (ancestor === null) {
    if (aria.Utils.matches(currentNode.parentNode, selector)) {
      ancestor = currentNode.parentNode;
    } else {
      currentNode = currentNode.parentNode;
    }
  }

  return ancestor;
};

aria.Utils.hasClass = function (element, className) {
  return new RegExp('(\\s|^)' + className + '(\\s|$)').test(element.className);
};

aria.Utils.addClass = function (element, className) {
  if (!aria.Utils.hasClass(element, className)) {
    element.className += ' ' + className;
  }
};

aria.Utils.removeClass = function (element, className) {
  var classRegex = new RegExp('(\\s|^)' + className + '(\\s|$)');
  element.className = element.className.replace(classRegex, ' ').trim();
};

aria.Utils.bindMethods = function (object /* , ...methodNames */) {
  var methodNames = Array.prototype.slice.call(arguments, 1);
  methodNames.forEach(function (method) {
    object[method] = object[method].bind(object);
  });
};

body {
  background: #fafafa;
  font-family: Helvetica, Arial, sans-serif;
  color: #000;
}

#side-panel {
  box-sizing: border-box;
  display: inline-block;
  padding-left: 1.5em;
  vertical-align: top;
  width: 29%;
}

#delay-time-select {
  display: block;
  margin-top: 5px;
  width: 10em;
}

#main-content {
  display: inline-block;
  vertical-align: top;
  min-width: 250px;
  width: 70%;
}

#restaurant-feed {
  max-width: 100%;
  width: 500px;
}

@media screen and (max-width: 560px) {
  #main-content {
    width: 100%;
  }
}

.restaurant-item {
  background: white;
  box-shadow: 1px 1px 6px #bbb;
  margin-bottom: 15px;
  padding-top: 15px;
}

.restaurant-details {
  display: inline-block;
  margin-bottom: 10px;
  padding-left: 15px;
  vertical-align: top;
  width: 55%;
}

.restaurant-name {
  font-size: 18px;
  margin-bottom: 2px;
}

.restaurant-star-img {
  width: 90px;
}

.restaurant-type {
  color: black;
  font-size: 13px;
}

.bookmark-button {
  height: 24px;
}

.location-block {
  color: black;
  display: inline-block;
  vertical-align: top;
  margin: 0 15px 10px;
  font-size: 14px;
  line-height: 1.3em;
}

.restaurant-actions {
  box-sizing: border-box;
  background: #a2afbc;
  padding: 10px;
  width: 100%;
}

.restaurant-rating svg g {
  color: #ffde00;
}

.restaurant-rating svg .star {
  stroke-width: 2px;
  stroke: #f8951d;
  fill-opacity: 0;
}

.restaurant-rating[data-rating-value="1"] svg .star-1 .star {
  fill: currentcolor;
  fill-opacity: 1;
}

.restaurant-rating[data-rating-value="2"] svg .star-2 .star {
  fill: currentcolor;
  fill-opacity: 1;
}

.restaurant-rating[data-rating-value="3"] svg .star-3 .star {
  fill: currentcolor;
  fill-opacity: 1;
}

.restaurant-rating[data-rating-value="4"] svg .star-4 .star {
  fill: currentcolor;
  fill-opacity: 1;
}

.restaurant-rating[data-rating-value="5"] svg .star-5 .star {
  fill: currentcolor;
  fill-opacity: 1;
}

@media (forced-colors: active) {
  .restaurant-rating svg g {
    color: currentcolor;
  }

  .restaurant-rating svg .star {
    stroke: currentcolor;
  }
}

